import type { VisualizationMode } from "./index";
import type { CollectiveState, DisplayConfig, PageContext, PlutchikEmotion } from "../state/types";
import { PLUTCHIK_EMOTIONS } from "../state/types";

const EMOTION_EMOJI: Record<PlutchikEmotion, string> = {
  joy:          "😄",
  trust:        "🤝",
  fear:         "😨",
  surprise:     "😮",
  sadness:      "😢",
  disgust:      "🤢",
  anger:        "😠",
  anticipation: "🤩",
};

const NS = "http://www.w3.org/2000/svg";
const W = 240;
const H = 140;
const PAD = 8;

// Optimal grid cell size for n items
function gridLayout(n: number): { cols: number; rows: number; cellW: number; cellH: number } {
  if (n === 0) return { cols: 0, rows: 0, cellW: 0, cellH: 0 };
  let bestCols = 1, bestCell = 0;
  for (let cols = 1; cols <= n; cols++) {
    const rows = Math.ceil(n / cols);
    const cell = Math.min((W - PAD) / cols - PAD, (H - PAD) / rows - PAD);
    if (cell > bestCell) { bestCell = cell; bestCols = cols; }
  }
  const bestRows = Math.ceil(n / bestCols);
  return { cols: bestCols, rows: bestRows, cellW: (W - PAD) / bestCols, cellH: (H - PAD) / bestRows };
}

function cellCenter(i: number, cols: number, cellW: number, cellH: number): { x: number; y: number } {
  const col = i % cols;
  const row = Math.floor(i / cols);
  return { x: PAD + col * cellW + cellW / 2, y: PAD + row * cellH + cellH / 2 };
}

export class EmojiViz implements VisualizationMode {
  id = "emoji";
  name = "Emoji";

  private svg: SVGSVGElement | null = null;
  private emojiEls: SVGTextElement[] = [];
  private bgEls: SVGRectElement[] = [];
  private animFrame: number | null = null;
  private phases: number[] = [];
  private lastState: CollectiveState | null = null;
  private lastConfig: DisplayConfig | null = null;
  private lastCount = -1;

  mount(container: HTMLElement, _config: DisplayConfig) {
    const svg = document.createElementNS(NS, "svg");
    svg.setAttribute("viewBox", `0 0 ${W} ${H}`);
    svg.setAttribute("preserveAspectRatio", "xMidYMid meet");
    svg.style.cssText = "width:100%;height:100%;display:block;";
    container.appendChild(svg);
    this.svg = svg;
    this.animate();
  }

  update(state: CollectiveState, config: DisplayConfig, _context?: PageContext) {
    this.lastState  = state;
    this.lastConfig = config;
    if (state.participantEmotions.length !== this.lastCount) {
      this.rebuild(state);
    }
  }

  unmount() {
    if (this.animFrame) cancelAnimationFrame(this.animFrame);
    this.svg?.remove();
    this.svg = null;
    this.emojiEls = [];
    this.bgEls = [];
    this.phases = [];
  }

  private rebuild(state: CollectiveState) {
    if (!this.svg) return;
    this.svg.innerHTML = "";
    this.emojiEls = [];
    this.bgEls = [];
    this.phases = [];

    const n = state.participantEmotions.length;
    this.lastCount = n;
    if (n === 0) return;

    const { cols, cellW, cellH } = gridLayout(n);
    const fontSize = Math.min(cellW, cellH) * 0.55;

    state.participantEmotions.forEach((emotions, i) => {
      const { x, y } = cellCenter(i, cols, cellW, cellH);

      // Subtle pill background
      const bg = document.createElementNS(NS, "rect");
      const bw = Math.min(cellW - 6, fontSize * 1.6);
      const bh = Math.min(cellH - 6, fontSize * 1.4);
      bg.setAttribute("x", String(x - bw / 2));
      bg.setAttribute("y", String(y - bh / 2));
      bg.setAttribute("width", String(bw));
      bg.setAttribute("height", String(bh));
      bg.setAttribute("rx", String(bh / 2));
      bg.setAttribute("fill", "rgba(0,0,0,0.04)");
      this.svg!.appendChild(bg);
      this.bgEls.push(bg);

      // Pick primary emoji — if no emotions, show neutral
      const emoji = emotions.length > 0 ? EMOTION_EMOJI[emotions[0] as PlutchikEmotion] : "😶";

      const text = document.createElementNS(NS, "text");
      text.setAttribute("x", String(x));
      text.setAttribute("y", String(y));
      text.setAttribute("text-anchor", "middle");
      text.setAttribute("dominant-baseline", "central");
      text.setAttribute("font-size", String(fontSize));
      text.textContent = emoji;
      this.svg!.appendChild(text);
      this.emojiEls.push(text);

      this.phases.push(Math.random() * Math.PI * 2);
    });
  }

  private animate() {
    this.animFrame = requestAnimationFrame(() => {
      const s   = this.lastState;
      const cfg = this.lastConfig;
      if (s && cfg && this.svg) {
        const n = s.participantEmotions.length;
        const { cols, cellW, cellH } = gridLayout(n);
        const fontSize = n > 0 ? Math.min(cellW, cellH) * 0.55 : 20;
        const speed = 0.018 * cfg.motion;

        this.emojiEls.forEach((text, i) => {
          const emotions = s.participantEmotions[i] ?? [];
          const emoji = emotions.length > 0 ? EMOTION_EMOJI[emotions[0] as PlutchikEmotion] : "😶";
          text.textContent = emoji;

          this.phases[i] = (this.phases[i] + speed) % (Math.PI * 2);
          const bob = Math.sin(this.phases[i]) * 1.8 * cfg.motion;
          const scale = 1 + Math.sin(this.phases[i] * 1.3) * 0.04 * cfg.motion;
          const { x, y } = cellCenter(i, cols, cellW, cellH);

          text.setAttribute("font-size", String(fontSize * scale));
          text.setAttribute("x", String(x));
          text.setAttribute("y", String(y + bob));

          const bg = this.bgEls[i];
          if (bg) {
            const bw = Math.min(cellW - 6, fontSize * 1.6);
            const bh = Math.min(cellH - 6, fontSize * 1.4);
            bg.setAttribute("x", String(x - bw / 2));
            bg.setAttribute("y", String(y - bh / 2 + bob));
          }
        });

        // Show aggregate emotion counts as a legend strip when >1 unique emotion
        this.updateLegend(s);
      }
      this.animate();
    });
  }

  private legendEls: SVGElement[] = [];

  private updateLegend(s: CollectiveState) {
    // Remove old legend
    this.legendEls.forEach((el) => el.remove());
    this.legendEls = [];
    if (!this.svg || s.participantEmotions.length === 0) return;

    // Count emoji frequencies
    const counts: Partial<Record<PlutchikEmotion, number>> = {};
    for (const emotions of s.participantEmotions) {
      for (const e of emotions) {
        counts[e as PlutchikEmotion] = (counts[e as PlutchikEmotion] ?? 0) + 1;
      }
    }

    const entries = PLUTCHIK_EMOTIONS
      .filter((e) => (counts[e] ?? 0) > 0)
      .map((e) => ({ e, count: counts[e]!, emoji: EMOTION_EMOJI[e] }));

    if (entries.length <= 1) return;

    // Small legend row at bottom
    const legendY = H - 10;
    const slotW = W / entries.length;
    entries.forEach(({ emoji, count }, i) => {
      const x = slotW * i + slotW / 2;

      const t = document.createElementNS(NS, "text");
      t.setAttribute("x", String(x));
      t.setAttribute("y", String(legendY));
      t.setAttribute("text-anchor", "middle");
      t.setAttribute("dominant-baseline", "central");
      t.setAttribute("font-size", "9");
      t.textContent = `${emoji} ${count}`;
      t.setAttribute("fill", "rgba(0,0,0,0.45)");
      this.svg!.appendChild(t);
      this.legendEls.push(t);
    });
  }
}
