import type { CollectiveState, DisplayConfig, PageContext, PlacementMode } from "../state/types";
import type { VisualizationMode } from "../visualizations/index";
import { WeatherViz }        from "../visualizations/weather";
import { PulseViz }          from "../visualizations/pulse";
import { PlantViz }          from "../visualizations/plant";
import { TaskNativeCodeViz } from "../visualizations/taskNativeCode";
import { PlutchikWheelViz }  from "../visualizations/plutchikWheel";
import { ParticipantsViz }   from "../visualizations/participants";
import { BstViz }            from "../visualizations/bst";
import { EmojiViz }          from "../visualizations/emoji";

const VIZ_MAP: Record<string, () => VisualizationMode> = {
  weather:        () => new WeatherViz(),
  pulse:          () => new PulseViz(),
  plant:          () => new PlantViz(),
  taskNativeCode: () => new TaskNativeCodeViz(),
  plutchikWheel:  () => new PlutchikWheelViz(),
  participants:   () => new ParticipantsViz(),
  bst:            () => new BstViz(),
  emoji:          () => new EmojiViz(),
};

// Minimum widget dimensions while resizing
const MIN_W = 120;
const MIN_H = 80;

/**
 * OverlayHost — the floating widget injected into the host page.
 *
 * Shadow DOM isolates styles. The widget has:
 *   - A drag handle (top strip) — grab and move anywhere on screen
 *   - A resize grip (bottom-right corner) — drag to resize
 *   - A viz container (#qs-viz) — where visualisations mount
 *
 * Position/size state:
 *   applyPlacement() sets the initial position from the side panel's placement
 *   mode. Once the user drags or resizes, those dimensions are locked until
 *   the placement mode changes (which snaps back to the new preset).
 *
 * To change preset sizes, edit the switch cases in applyPlacement().
 */
export class OverlayHost {
  private shadow: ShadowRoot;
  private container: HTMLElement;
  private vizContainer: HTMLElement;
  private dragHandle: HTMLElement;
  private resizeHandle: HTMLElement;
  private host: HTMLElement;

  private observer: MutationObserver | null = null;
  private currentViz: VisualizationMode | null = null;
  private currentMode = "";

  // Track whether the user has manually moved/resized since last placement change
  private positionLocked = false;
  private sizeLocked = false;
  private lastPlacement: PlacementMode | null = null;

  constructor() {
    this.host = document.createElement("div");
    this.host.id = "kindred-host";
    // Attach to <html> not <body>: body transforms (common on SPAs) would
    // break position:fixed on any descendant, but <html> is rarely transformed.
    this.host.style.cssText =
      "all:initial;position:fixed;top:0;left:0;width:0;height:0;overflow:visible;pointer-events:none;z-index:2147483647;";
    document.documentElement.appendChild(this.host);
    this.shadow = this.host.attachShadow({ mode: "open" });

    // Re-insert the host if the page removes it (e.g. aggressive DOM resets)
    this.observer = new MutationObserver(() => {
      if (!document.documentElement.contains(this.host)) {
        document.documentElement.appendChild(this.host);
      }
    });
    this.observer.observe(document.documentElement, { childList: true, subtree: false });

    const style = document.createElement("style");
    style.textContent = `
      :host { all: initial; }

      #qs-container {
        position: fixed;
        z-index: 2147483647;
        pointer-events: all;
        overflow: hidden;
        box-shadow: 0 4px 32px rgba(0,0,0,0.5);
        background: #111;
        border-radius: 10px;
        display: flex;
        flex-direction: column;
        font-family: sans-serif;
        transition: width 0.25s ease, height 0.25s ease, opacity 0.25s ease;
      }

      @media (prefers-color-scheme: light) {
        #qs-container {
          background: #ffffff;
          box-shadow: 0 4px 32px rgba(0,0,0,0.18);
          border: 1px solid rgba(0,0,0,0.1);
        }
        #qs-drag-handle {
          background: rgba(0,0,0,0.03);
          border-bottom: 1px solid rgba(0,0,0,0.08);
        }
        #qs-drag-handle:hover { background: rgba(0,0,0,0.07); }
        .qs-grip-dot { background: rgba(0,0,0,0.25); }
      }

      /* ── Drag handle ── */
      #qs-drag-handle {
        height: 16px;
        flex-shrink: 0;
        cursor: grab;
        background: rgba(255,255,255,0.04);
        border-bottom: 1px solid rgba(255,255,255,0.07);
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 3px;
        user-select: none;
        -webkit-user-select: none;
      }
      #qs-drag-handle:hover { background: rgba(255,255,255,0.09); }
      #qs-drag-handle.grabbing { cursor: grabbing; }

      /* Grip dots */
      .qs-grip-dot {
        width: 3px;
        height: 3px;
        border-radius: 50%;
        background: rgba(255,255,255,0.25);
      }

      /* ── Viz area ── */
      #qs-viz {
        flex: 1;
        position: relative;
        overflow: hidden;
        min-height: 0; /* required for flex children with overflow */
      }

      /* ── Resize handle ── */
      #qs-resize-handle {
        position: absolute;
        bottom: 0;
        right: 0;
        width: 16px;
        height: 16px;
        cursor: nwse-resize;
        z-index: 1;
        opacity: 0.35;
        transition: opacity 0.15s;
      }
      #qs-resize-handle:hover { opacity: 0.75; }
      #qs-resize-handle svg { width: 100%; height: 100%; }
    `;
    this.shadow.appendChild(style);

    // ── Container ──────────────────────────────────────────────────────────
    this.container = document.createElement("div");
    this.container.id = "qs-container";
    this.shadow.appendChild(this.container);

    // ── Drag handle ────────────────────────────────────────────────────────
    this.dragHandle = document.createElement("div");
    this.dragHandle.id = "qs-drag-handle";
    // Render 6 grip dots
    for (let i = 0; i < 6; i++) {
      const dot = document.createElement("div");
      dot.className = "qs-grip-dot";
      this.dragHandle.appendChild(dot);
    }
    this.container.appendChild(this.dragHandle);

    // ── Viz container ──────────────────────────────────────────────────────
    this.vizContainer = document.createElement("div");
    this.vizContainer.id = "qs-viz";
    this.container.appendChild(this.vizContainer);

    // ── Resize handle (SVG grip icon) ──────────────────────────────────────
    this.resizeHandle = document.createElement("div");
    this.resizeHandle.id = "qs-resize-handle";
    this.resizeHandle.innerHTML = `
      <svg viewBox="0 0 16 16" fill="none">
        <line x1="4" y1="14" x2="14" y2="4"  stroke="white" stroke-width="1.5" stroke-linecap="round"/>
        <line x1="8" y1="14" x2="14" y2="8"  stroke="white" stroke-width="1.5" stroke-linecap="round"/>
        <line x1="12" y1="14" x2="14" y2="12" stroke="white" stroke-width="1.5" stroke-linecap="round"/>
      </svg>`;
    this.container.appendChild(this.resizeHandle);

    this.setupDrag();
    this.setupResize();
  }

  // ── Drag ────────────────────────────────────────────────────────────────────

  private setupDrag() {
    let startX = 0, startY = 0, startLeft = 0, startTop = 0;

    const onMove = (e: MouseEvent) => {
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      // Clamp within viewport
      const maxLeft = window.innerWidth  - this.container.offsetWidth;
      const maxTop  = window.innerHeight - this.container.offsetHeight;
      this.container.style.left   = `${Math.max(0, Math.min(maxLeft, startLeft + dx))}px`;
      this.container.style.top    = `${Math.max(0, Math.min(maxTop,  startTop  + dy))}px`;
      this.container.style.right  = "";
      this.container.style.bottom = "";
    };

    const onUp = () => {
      this.dragHandle.classList.remove("grabbing");
      document.removeEventListener("mousemove", onMove);
      document.removeEventListener("mouseup", onUp);
    };

    this.dragHandle.addEventListener("mousedown", (e: MouseEvent) => {
      e.preventDefault();
      const rect  = this.container.getBoundingClientRect();
      startX      = e.clientX;
      startY      = e.clientY;
      startLeft   = rect.left;
      startTop    = rect.top;
      this.positionLocked = true;       // user has taken control of position
      this.dragHandle.classList.add("grabbing");
      this.container.style.transition = "none"; // no easing while dragging
      document.addEventListener("mousemove", onMove);
      document.addEventListener("mouseup", onUp);
    });
  }

  // ── Resize ──────────────────────────────────────────────────────────────────

  private setupResize() {
    let startX = 0, startY = 0, startW = 0, startH = 0;

    const onMove = (e: MouseEvent) => {
      const newW = Math.max(MIN_W, startW + (e.clientX - startX));
      const newH = Math.max(MIN_H, startH + (e.clientY - startY));
      this.container.style.width  = `${newW}px`;
      this.container.style.height = `${newH}px`;
    };

    const onUp = () => {
      this.container.style.transition = ""; // restore transition
      document.removeEventListener("mousemove", onMove);
      document.removeEventListener("mouseup", onUp);
    };

    this.resizeHandle.addEventListener("mousedown", (e: MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      const rect  = this.container.getBoundingClientRect();
      startX      = e.clientX;
      startY      = e.clientY;
      startW      = rect.width;
      startH      = rect.height;
      this.sizeLocked = true;           // user has taken control of size
      this.container.style.transition = "none";
      document.addEventListener("mousemove", onMove);
      document.addEventListener("mouseup", onUp);
    });
  }

  // ── Public API ──────────────────────────────────────────────────────────────

  update(collective: CollectiveState, config: DisplayConfig, context: PageContext) {
    this.applyPlacement(config);

    const needsRemount = !this.currentViz || this.currentMode !== config.mode;
    if (needsRemount) {
      this.currentViz?.unmount();
      this.vizContainer.innerHTML = "";
      const factory = VIZ_MAP[config.mode] ?? VIZ_MAP["plutchikWheel"];
      this.currentViz = factory();
      this.currentMode = config.mode;
      this.currentViz.mount(this.vizContainer, config);
    }

    this.currentViz?.update(collective, config, context);
  }

  destroy() {
    this.observer?.disconnect();
    this.currentViz?.unmount();
    this.host.remove();
  }

  // ── Placement ───────────────────────────────────────────────────────────────

  /**
   * Applies preset position and size from the side panel.
   * Once the user manually moves or resizes, those dimensions are locked
   * until the placement mode itself changes (which resets both locks).
   */
  private applyPlacement(config: DisplayConfig) {
    const placementChanged = config.placement !== this.lastPlacement;

    if (placementChanged) {
      // User switched placement mode → snap to new preset, clear locks
      this.positionLocked = false;
      this.sizeLocked     = false;
      this.lastPlacement  = config.placement;
      this.container.style.transition = ""; // re-enable smooth transition
    }

    const el = this.container;

    // Always update opacity (not considered a position/size property)
    el.style.opacity = config.placement === "overlay" ? "0.88" : "1";

    // Apply position (skip if user has dragged)
    if (!this.positionLocked) {
      el.style.top    = "";
      el.style.bottom = "";
      el.style.left   = "";
      el.style.right  = "";
      el.style.borderRadius = "10px";

      switch (config.placement) {
        case "corner":
          el.style.bottom = "20px";
          el.style.right  = "20px";
          break;
        case "edge":
          el.style.top          = "50%";
          el.style.right        = "0";
          el.style.transform    = "translateY(-50%)";
          el.style.borderRadius = "10px 0 0 10px";
          break;
        case "overlay":
          el.style.top       = "50%";
          el.style.left      = "50%";
          el.style.transform = "translate(-50%, -50%)";
          break;
      }
    }

    // Apply size (skip if user has resized)
    if (!this.sizeLocked) {
      switch (config.placement) {
        case "corner":
          el.style.width  = "200px";
          el.style.height = "130px";
          break;
        case "edge":
          el.style.width  = "200px";
          el.style.height = "150px";
          break;
        case "overlay":
          el.style.width  = "280px";
          el.style.height = "190px";
          break;
      }
    }
  }
}
