import type { VisualizationMode } from "./index";
import type { CollectiveState, DisplayConfig, PageContext, PlutchikEmotion } from "../state/types";
import { EMOTION_RGB } from "./participants";

function blendEmotions(emotions: PlutchikEmotion[]): string {
  if (emotions.length === 0) return "rgb(180,180,200)";
  let r = 0, g = 0, b = 0;
  for (const e of emotions) {
    const [er, eg, eb] = EMOTION_RGB[e];
    r += er; g += eg; b += eb;
  }
  return `rgb(${Math.round(r / emotions.length)},${Math.round(g / emotions.length)},${Math.round(b / emotions.length)})`;
}

// Level-order BST layout: node i has parent floor((i-1)/2)
function bstLayout(n: number, w: number, h: number): { cx: number; cy: number }[] {
  if (n === 0) return [];
  const numLevels = Math.floor(Math.log2(n)) + 1;
  const padV = h * 0.12;
  const usableH = h - padV * 2;

  return Array.from({ length: n }, (_, i) => {
    const level = Math.floor(Math.log2(i + 1));
    const posInLevel = i - ((1 << level) - 1);
    const countAtLevel = 1 << level;
    const cx = (posInLevel + 0.5) / countAtLevel * w;
    const cy = padV + (numLevels === 1 ? usableH / 2 : (level / (numLevels - 1)) * usableH);
    return { cx, cy };
  });
}

const NS = "http://www.w3.org/2000/svg";

export class BstViz implements VisualizationMode {
  id = "bst";
  name = "Tree";

  private svg: SVGSVGElement | null = null;
  private edgeGroup: SVGGElement | null = null;
  private nodeGroup: SVGGElement | null = null;
  private animFrame: number | null = null;
  private phases: number[] = [];
  private lastState: CollectiveState | null = null;
  private lastConfig: DisplayConfig | null = null;
  private lastCount = -1;
  private nodeEls: SVGCircleElement[] = [];

  private readonly W = 240;
  private readonly H = 140;
  private readonly NODE_R = 7;

  mount(container: HTMLElement, _config: DisplayConfig) {
    const svg = document.createElementNS(NS, "svg");
    svg.setAttribute("viewBox", `0 0 ${this.W} ${this.H}`);
    svg.setAttribute("preserveAspectRatio", "xMidYMid meet");
    svg.style.cssText = "width:100%;height:100%;display:block;";

    const bg = document.createElementNS(NS, "rect");
    bg.setAttribute("width", String(this.W));
    bg.setAttribute("height", String(this.H));
    bg.setAttribute("fill", "transparent");
    svg.appendChild(bg);

    this.edgeGroup = document.createElementNS(NS, "g");
    this.nodeGroup = document.createElementNS(NS, "g");
    svg.appendChild(this.edgeGroup);
    svg.appendChild(this.nodeGroup);

    container.appendChild(svg);
    this.svg = svg;
    this.animate();
  }

  update(state: CollectiveState, config: DisplayConfig, _context?: PageContext) {
    this.lastState  = state;
    this.lastConfig = config;
    if (state.participantEmotions.length !== this.lastCount) {
      this.rebuild(state);
    }
  }

  unmount() {
    if (this.animFrame) cancelAnimationFrame(this.animFrame);
    this.svg?.remove();
    this.svg = null;
    this.edgeGroup = null;
    this.nodeGroup = null;
    this.nodeEls = [];
    this.phases = [];
  }

  private rebuild(state: CollectiveState) {
    const n = state.participantEmotions.length;
    this.lastCount = n;
    this.nodeEls = [];
    this.phases = [];
    if (!this.edgeGroup || !this.nodeGroup) return;

    this.edgeGroup.innerHTML = "";
    this.nodeGroup.innerHTML = "";

    const positions = bstLayout(n, this.W, this.H);

    // Draw edges first (parent → child)
    for (let i = 1; i < n; i++) {
      const parent = Math.floor((i - 1) / 2);
      const p = positions[parent];
      const c = positions[i];
      const line = document.createElementNS(NS, "line");
      line.setAttribute("x1", String(p.cx));
      line.setAttribute("y1", String(p.cy));
      line.setAttribute("x2", String(c.cx));
      line.setAttribute("y2", String(c.cy));
      line.setAttribute("stroke", "rgba(180,180,200,0.5)");
      line.setAttribute("stroke-width", "1");
      this.edgeGroup.appendChild(line);
    }

    // Draw nodes
    positions.forEach(({ cx, cy }, i) => {
      const color = blendEmotions(state.participantEmotions[i] ?? []);
      const circle = document.createElementNS(NS, "circle");
      circle.setAttribute("cx", String(cx));
      circle.setAttribute("cy", String(cy));
      circle.setAttribute("r", String(this.NODE_R));
      circle.setAttribute("fill", color);
      circle.setAttribute("opacity", "0.9");
      this.nodeGroup!.appendChild(circle);
      this.nodeEls.push(circle);
      this.phases.push(Math.random() * Math.PI * 2);
    });
  }

  private animate() {
    this.animFrame = requestAnimationFrame(() => {
      const s   = this.lastState;
      const cfg = this.lastConfig;
      if (s && cfg) {
        this.nodeEls.forEach((circle, i) => {
          const emotions = s.participantEmotions[i] ?? [];
          const color = blendEmotions(emotions);
          this.phases[i] = (this.phases[i] + 0.025 * cfg.motion) % (Math.PI * 2);
          const breathe = 1 + Math.sin(this.phases[i]) * 0.12 * cfg.motion;
          circle.setAttribute("r", String(this.NODE_R * breathe));
          circle.setAttribute("fill", color);
        });
      }
      this.animate();
    });
  }
}
