import type { VisualizationMode } from "./index";
import type { CollectiveState, DisplayConfig, PageContext, PlutchikEmotion } from "../state/types";
import { PLUTCHIK_EMOTIONS } from "../state/types";

/**
 * Participants — visualises how many people feel each emotion, with three views
 * controlled by the granularity slider:
 *
 *   0 – 0.33  Individual:  one circle per person, colored by their selected emotions
 *   0.33–0.67 Grouped:     one circle per emotion present in the session, sized by
 *                          how many people selected it; arranged in a Plutchik ring
 *   0.67–1    Aggregated:  single circle blending all participants' emotions
 *
 * Other mappings:
 *   solidarity   → ring opacity
 *   motion cfg   → pulse speed
 *   abstraction  → solid fill vs. ring-only (individual mode only)
 */

// ── Emotion → RGB ──────────────────────────────────────────────────────────────
export const EMOTION_RGB: Record<PlutchikEmotion, [number, number, number]> = {
  joy:          [245, 200,  66],
  trust:        [ 93, 191, 111],
  fear:         [168, 200,  66],
  surprise:     [ 66, 200, 200],
  sadness:      [ 66, 134, 200],
  disgust:      [139,  95, 200],
  anger:        [200,  66,  66],
  anticipation: [200, 122,  66],
};

function blendEmotions(emotions: PlutchikEmotion[]): { color: string; arousal: number } {
  if (emotions.length === 0) return { color: "rgb(80,90,110)", arousal: 0.1 };

  let r = 0, g = 0, b = 0;
  for (const e of emotions) {
    const [er, eg, eb] = EMOTION_RGB[e];
    r += er; g += eg; b += eb;
  }
  r = Math.round(r / emotions.length);
  g = Math.round(g / emotions.length);
  b = Math.round(b / emotions.length);

  const activating = new Set(["anger", "fear", "anticipation", "surprise", "joy"]);
  const arousal = Math.min(1, emotions.filter((e) => activating.has(e)).length * 0.28);

  return { color: `rgb(${r},${g},${b})`, arousal: Math.max(0.05, arousal) };
}

function blendRecord(emotions: Record<PlutchikEmotion, number>): string {
  let r = 0, g = 0, b = 0, total = 0;
  for (const e of PLUTCHIK_EMOTIONS) {
    const w = emotions[e];
    if (w <= 0) continue;
    const [er, eg, eb] = EMOTION_RGB[e];
    r += er * w; g += eg * w; b += eb * w; total += w;
  }
  if (total === 0) return "rgb(80,90,110)";
  return `rgb(${Math.round(r/total)},${Math.round(g/total)},${Math.round(b/total)})`;
}

// ── Layout helpers ────────────────────────────────────────────────────────────

type CircleLayout = { cx: number; cy: number; r: number };

function computeGridLayout(n: number, w: number, h: number): CircleLayout[] {
  if (n === 0) return [];
  const pad = 6;
  let bestR = 0, bestCols = 1;
  for (let cols = 1; cols <= n; cols++) {
    const rows = Math.ceil(n / cols);
    const rW = (w - pad * (cols + 1)) / (2 * cols);
    const rH = (h - pad * (rows + 1)) / (2 * rows);
    const r = Math.min(rW, rH);
    if (r > bestR) { bestR = r; bestCols = cols; }
  }
  const bestRows = Math.ceil(n / bestCols);
  const r = bestR;
  const gridW = bestCols * 2 * r + (bestCols - 1) * pad;
  const gridH = bestRows * 2 * r + (bestRows - 1) * pad;
  const offX = (w - gridW) / 2 + r;
  const offY = (h - gridH) / 2 + r;
  const positions: CircleLayout[] = [];
  for (let i = 0; i < n; i++) {
    const col = i % bestCols;
    const row = Math.floor(i / bestCols);
    positions.push({ cx: offX + col * (2 * r + pad), cy: offY + row * (2 * r + pad), r });
  }
  return positions;
}

// 8 fixed positions arranged in a ring (one per Plutchik emotion)
function ringPosition(index: number, w: number, h: number): { cx: number; cy: number } {
  const cx0 = w / 2, cy0 = h / 2;
  const rx = w * 0.34, ry = h * 0.34;
  const angle = (index / 8) * Math.PI * 2 - Math.PI / 2;
  return { cx: cx0 + rx * Math.cos(angle), cy: cy0 + ry * Math.sin(angle) };
}

// ── Granularity thresholds ────────────────────────────────────────────────────

type GranMode = "individual" | "grouped" | "aggregated";

function getGranMode(granularity: number): GranMode {
  if (granularity < 0.33) return "individual";
  if (granularity < 0.67) return "grouped";
  return "aggregated";
}

// ── Visualisation ─────────────────────────────────────────────────────────────

export class ParticipantsViz implements VisualizationMode {
  id = "participants";
  name = "People";

  private svg: SVGSVGElement | null = null;
  private bgRect: SVGRectElement | null = null;
  private animFrame: number | null = null;
  private phases: number[] = [];
  private lastState: CollectiveState | null = null;
  private lastConfig: DisplayConfig | null = null;
  private lastGranMode: GranMode | null = null;
  private lastCount = -1;

  // Per-mode circle elements
  private circleEls: SVGCircleElement[] = [];
  private ringEls: SVGCircleElement[] = [];

  private viewW = 200;
  private viewH = 120;

  private isDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
  private mql = window.matchMedia("(prefers-color-scheme: dark)");

  mount(container: HTMLElement, _config: DisplayConfig) {
    const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
    svg.setAttribute("viewBox", `0 0 ${this.viewW} ${this.viewH}`);
    svg.setAttribute("preserveAspectRatio", "xMidYMid meet");
    svg.style.cssText = "width:100%;height:100%;display:block;";

    const bg = document.createElementNS("http://www.w3.org/2000/svg", "rect");
    bg.setAttribute("width",  String(this.viewW));
    bg.setAttribute("height", String(this.viewH));
    bg.setAttribute("rx", "8");
    bg.setAttribute("fill", this.isDark ? "#000000" : "#ffffff");
    svg.appendChild(bg);
    this.bgRect = bg;

    const group = document.createElementNS("http://www.w3.org/2000/svg", "g");
    group.setAttribute("id", "pcGroup");
    svg.appendChild(group);

    container.appendChild(svg);
    this.svg = svg;

    this.mql.addEventListener("change", this.onSchemeChange);
    this.animate();
  }

  private onSchemeChange = (e: MediaQueryListEvent) => {
    this.isDark = e.matches;
    if (this.bgRect) this.bgRect.setAttribute("fill", this.isDark ? "#000000" : "#ffffff");
  };

  update(state: CollectiveState, config: DisplayConfig, _context?: PageContext) {
    this.lastState  = state;
    this.lastConfig = config;
    const granMode  = getGranMode(config.granularity);
    const countChanged = state.participantEmotions.length !== this.lastCount;
    const modeChanged  = granMode !== this.lastGranMode;
    if (countChanged || modeChanged) {
      this.rebuild(state, granMode);
      this.lastGranMode = granMode;
    }
  }

  unmount() {
    if (this.animFrame) cancelAnimationFrame(this.animFrame);
    this.mql.removeEventListener("change", this.onSchemeChange);
    this.svg?.remove();
    this.svg = null;
    this.bgRect = null;
    this.circleEls = [];
    this.ringEls   = [];
  }

  // ── Rebuild ────────────────────────────────────────────────────────────────

  private rebuild(state: CollectiveState, mode: GranMode) {
    const svg = this.svg;
    if (!svg) return;
    const group = svg.getElementById("pcGroup");
    if (!group) return;

    group.innerHTML = "";
    this.circleEls = [];
    this.ringEls   = [];
    this.phases    = [];
    this.lastCount = state.participantEmotions.length;

    if (mode === "individual") {
      this.buildIndividual(group, state);
    } else if (mode === "grouped") {
      this.buildGrouped(group, state);
    } else {
      this.buildAggregated(group);
    }
  }

  private buildIndividual(group: Element, state: CollectiveState) {
    const n = state.participantEmotions.length;
    const layout = computeGridLayout(n, this.viewW, this.viewH);
    layout.forEach(({ cx, cy, r }) => {
      const ring = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      ring.setAttribute("cx", String(cx));
      ring.setAttribute("cy", String(cy));
      ring.setAttribute("r",  String(r));
      ring.setAttribute("fill", "none");
      ring.setAttribute("stroke-width", "1.5");
      group.appendChild(ring);
      this.ringEls.push(ring);

      const circle = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      circle.setAttribute("cx", String(cx));
      circle.setAttribute("cy", String(cy));
      circle.setAttribute("r",  String(r));
      group.appendChild(circle);
      this.circleEls.push(circle);

      this.phases.push(Math.random() * Math.PI * 2);
    });
  }

  private buildGrouped(group: Element, state: CollectiveState) {
    // One circle per emotion that at least one person selected,
    // arranged in a Plutchik ring, sized by selection count
    PLUTCHIK_EMOTIONS.forEach((emotion, idx) => {
      const count = state.participantEmotions.filter((s) => s.includes(emotion)).length;
      if (count === 0) return;

      const { cx, cy } = ringPosition(idx, this.viewW, this.viewH);

      const ring = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      ring.setAttribute("cx", String(cx));
      ring.setAttribute("cy", String(cy));
      ring.setAttribute("r",  "0");
      ring.setAttribute("fill", "none");
      ring.setAttribute("stroke-width", "1.5");
      group.appendChild(ring);
      this.ringEls.push(ring);

      const circle = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      circle.setAttribute("cx", String(cx));
      circle.setAttribute("cy", String(cy));
      circle.setAttribute("r",  "0");
      // Store emotion name + count for render
      circle.dataset["emotion"] = emotion;
      circle.dataset["count"]   = String(count);
      group.appendChild(circle);
      this.circleEls.push(circle);
      this.ringEls.push(ring); // ring is already pushed above, but we need matching index

      this.phases.push(Math.random() * Math.PI * 2);
    });
    // Align ringEls with circleEls (they were pushed separately above, let's reset)
    // Simpler: rebuild both arrays together
    group.innerHTML = "";
    this.circleEls = [];
    this.ringEls   = [];
    this.phases    = [];

    PLUTCHIK_EMOTIONS.forEach((emotion, idx) => {
      const count = state.participantEmotions.filter((s) => s.includes(emotion)).length;
      if (count === 0) return;
      const { cx, cy } = ringPosition(idx, this.viewW, this.viewH);

      const ring = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      ring.setAttribute("cx", String(cx));
      ring.setAttribute("cy", String(cy));
      ring.setAttribute("fill", "none");
      ring.setAttribute("stroke-width", "1.5");
      group.appendChild(ring);
      this.ringEls.push(ring);

      const circle = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      circle.setAttribute("cx", String(cx));
      circle.setAttribute("cy", String(cy));
      circle.dataset["emotion"] = emotion;
      circle.dataset["count"]   = String(count);
      group.appendChild(circle);
      this.circleEls.push(circle);

      this.phases.push(Math.random() * Math.PI * 2);
    });
  }

  private buildAggregated(group: Element) {
    const cx = this.viewW / 2, cy = this.viewH / 2;

    const ring = document.createElementNS("http://www.w3.org/2000/svg", "circle");
    ring.setAttribute("cx", String(cx));
    ring.setAttribute("cy", String(cy));
    ring.setAttribute("fill", "none");
    ring.setAttribute("stroke-width", "2");
    group.appendChild(ring);
    this.ringEls.push(ring);

    const circle = document.createElementNS("http://www.w3.org/2000/svg", "circle");
    circle.setAttribute("cx", String(cx));
    circle.setAttribute("cy", String(cy));
    group.appendChild(circle);
    this.circleEls.push(circle);

    this.phases.push(0);
  }

  // ── Animation ──────────────────────────────────────────────────────────────

  private animate() {
    this.animFrame = requestAnimationFrame(() => {
      const s   = this.lastState;
      const cfg = this.lastConfig;
      if (s && cfg) {
        const mode = getGranMode(cfg.granularity);
        if (mode === "individual") this.renderIndividual(s, cfg);
        else if (mode === "grouped") this.renderGrouped(s, cfg);
        else this.renderAggregated(s, cfg);
      }
      this.animate();
    });
  }

  private renderIndividual(s: CollectiveState, cfg: DisplayConfig) {
    const layout = computeGridLayout(s.participantEmotions.length, this.viewW, this.viewH);
    s.participantEmotions.forEach((emotions, i) => {
      const { color, arousal } = blendEmotions(emotions);
      const circle = this.circleEls[i];
      const ring   = this.ringEls[i];
      const pos    = layout[i];
      if (!circle || !ring || !pos) return;

      this.phases[i] = (this.phases[i] + arousal * 0.04 * cfg.motion) % (Math.PI * 2);
      const breathe = 1 + Math.sin(this.phases[i]) * 0.06 * cfg.motion;
      const finalR  = pos.r * breathe;

      const fillOpacity   = Math.max(0, 1 - cfg.abstraction * 0.85);
      const strokeOpacity = 0.3 + cfg.abstraction * 0.6;

      circle.setAttribute("r",       String(finalR));
      circle.setAttribute("fill",    color);
      circle.setAttribute("opacity", String(fillOpacity));

      ring.setAttribute("r",       String(finalR + 1.5));
      ring.setAttribute("stroke",  color);
      ring.setAttribute("opacity", String(s.solidarity * strokeOpacity));
    });
  }

  private renderGrouped(s: CollectiveState, cfg: DisplayConfig) {
    const n = Math.max(1, s.activeCount);
    this.circleEls.forEach((circle, i) => {
      const ring    = this.ringEls[i];
      const emotion = circle.dataset["emotion"] as PlutchikEmotion | undefined;
      const count   = parseInt(circle.dataset["count"] ?? "1", 10);
      if (!emotion || !ring) return;

      const [er, eg, eb] = EMOTION_RGB[emotion];
      const color = `rgb(${er},${eg},${eb})`;

      // Radius: proportional to sqrt(count/n) so area ∝ fraction
      const fraction = count / n;
      const maxR = Math.min(this.viewW, this.viewH) * 0.18;
      const baseR = maxR * (0.4 + 0.6 * Math.sqrt(fraction));

      this.phases[i] = (this.phases[i] + 0.03 * cfg.motion) % (Math.PI * 2);
      const breathe = 1 + Math.sin(this.phases[i]) * 0.05 * cfg.motion;
      const finalR  = baseR * breathe;

      circle.setAttribute("r",       String(finalR));
      circle.setAttribute("fill",    color);
      circle.setAttribute("opacity", String(0.75 + fraction * 0.2));

      ring.setAttribute("r",       String(finalR + 2));
      ring.setAttribute("stroke",  color);
      ring.setAttribute("stroke-width", String(1 + fraction));
      ring.setAttribute("opacity", String(s.solidarity * 0.6));
    });
  }

  private renderAggregated(s: CollectiveState, cfg: DisplayConfig) {
    const circle = this.circleEls[0];
    const ring   = this.ringEls[0];
    if (!circle || !ring) return;

    const color = blendRecord(s.emotions);
    this.phases[0] = (this.phases[0] + s.avgArousal * 0.03 * cfg.motion) % (Math.PI * 2);
    const maxR  = Math.min(this.viewW, this.viewH) * 0.38;
    const breathe = 1 + Math.sin(this.phases[0]) * 0.07 * cfg.motion;
    const finalR  = maxR * breathe;

    circle.setAttribute("r",       String(finalR));
    circle.setAttribute("fill",    color);
    circle.setAttribute("opacity", "0.85");

    ring.setAttribute("r",       String(finalR + 3));
    ring.setAttribute("stroke",  color);
    ring.setAttribute("stroke-width", "2");
    ring.setAttribute("opacity", String(s.solidarity * 0.7));
  }
}
