import type { VisualizationMode } from "./index";
import type { CollectiveState, DisplayConfig, PageContext, PlutchikEmotion } from "../state/types";
import { PLUTCHIK_EMOTIONS } from "../state/types";

/**
 * Plutchik Wheel — radial petal chart of the 8 primary emotions.
 *
 * Mappings:
 *   emotions[x]  → petal radius (min = hub, max = outer ring at intensity 1.0)
 *   solidarity   → overall petal opacity
 *   variance     → individual petal opacity variation
 *   motion cfg   → slow breathing pulse on petal sizes
 *   abstraction  → 0 = show emotion labels, 1 = hide labels
 */

const CX = 100;
const CY = 100;
const HUB_R = 14;
const MAX_R = 78;
const LABEL_R = 86;
const SECTOR_DEG = 360 / 8;

const COLORS: Record<PlutchikEmotion, string> = {
  joy:          "#FFD700",
  trust:        "#3DBE6A",
  fear:         "#9DC926",
  surprise:     "#1ECFCF",
  sadness:      "#2272D9",
  disgust:      "#7B3FC4",
  anger:        "#E03030",
  anticipation: "#E07820",
};

const LABELS: Record<PlutchikEmotion, string> = {
  joy:          "JOY",
  trust:        "TRUST",
  fear:         "FEAR",
  surprise:     "SURP.",
  sadness:      "SAD",
  disgust:      "DISG.",
  anger:        "ANGER",
  anticipation: "ANTIC.",
};

function polar(r: number, angleDeg: number): [number, number] {
  const rad = ((angleDeg - 90) * Math.PI) / 180;
  return [CX + r * Math.cos(rad), CY + r * Math.sin(rad)];
}

function petalPath(r: number, centerAngle: number): string {
  const half = SECTOR_DEG / 2;
  const [x1, y1] = polar(r, centerAngle - half);
  const [x2, y2] = polar(r, centerAngle + half);
  return `M ${CX} ${CY} L ${x1} ${y1} A ${r} ${r} 0 0 1 ${x2} ${y2} Z`;
}

function arcPath(r: number, centerAngle: number): string {
  const half = SECTOR_DEG / 2 - 1;
  const [x1, y1] = polar(r, centerAngle - half);
  const [x2, y2] = polar(r, centerAngle + half);
  return `M ${x1} ${y1} A ${r} ${r} 0 0 1 ${x2} ${y2}`;
}

export class PlutchikWheelViz implements VisualizationMode {
  id = "plutchikWheel";
  name = "Plutchik Wheel";

  private svg: SVGSVGElement | null = null;
  private animFrame: number | null = null;
  private phase = 0;
  private lastState: CollectiveState | null = null;
  private lastConfig: DisplayConfig | null = null;

  private petalEls: Partial<Record<PlutchikEmotion, SVGPathElement>> = {};
  private outerArcEls: Partial<Record<PlutchikEmotion, SVGPathElement>> = {};
  private labelEls: Partial<Record<PlutchikEmotion, SVGTextElement>> = {};

  private bgEl: SVGRectElement | null = null;
  private refRingEl: SVGCircleElement | null = null;
  private midRingEl: SVGCircleElement | null = null;
  private hubEl: SVGCircleElement | null = null;

  private isDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
  private mql = window.matchMedia("(prefers-color-scheme: dark)");

  mount(container: HTMLElement, _config: DisplayConfig) {
    const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
    svg.setAttribute("viewBox", "0 0 200 200");
    svg.setAttribute("preserveAspectRatio", "xMidYMid meet");
    svg.style.cssText = "width:100%;height:100%;display:block;";

    const bg = document.createElementNS("http://www.w3.org/2000/svg", "rect");
    bg.setAttribute("width", "200");
    bg.setAttribute("height", "200");
    bg.setAttribute("fill", this.isDark ? "#000000" : "#ffffff");
    svg.appendChild(bg);
    this.bgEl = bg;

    const refRing = document.createElementNS("http://www.w3.org/2000/svg", "circle");
    refRing.setAttribute("cx", String(CX));
    refRing.setAttribute("cy", String(CY));
    refRing.setAttribute("r", String(MAX_R));
    refRing.setAttribute("fill", "none");
    refRing.setAttribute("stroke", this.isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.06)");
    refRing.setAttribute("stroke-width", "1");
    svg.appendChild(refRing);
    this.refRingEl = refRing;

    const midRing = document.createElementNS("http://www.w3.org/2000/svg", "circle");
    midRing.setAttribute("cx", String(CX));
    midRing.setAttribute("cy", String(CY));
    midRing.setAttribute("r", String(HUB_R + (MAX_R - HUB_R) * 0.5));
    midRing.setAttribute("fill", "none");
    midRing.setAttribute("stroke", this.isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)");
    midRing.setAttribute("stroke-width", "1");
    svg.appendChild(midRing);
    this.midRingEl = midRing;

    PLUTCHIK_EMOTIONS.forEach((emotion, i) => {
      const centerAngle = i * SECTOR_DEG;

      const petal = document.createElementNS("http://www.w3.org/2000/svg", "path");
      petal.setAttribute("fill", COLORS[emotion]);
      petal.setAttribute("stroke", this.isDark ? "#000000" : "#ffffff");
      petal.setAttribute("stroke-width", "1");
      svg.appendChild(petal);
      this.petalEls[emotion] = petal;

      const arc = document.createElementNS("http://www.w3.org/2000/svg", "path");
      arc.setAttribute("fill", "none");
      arc.setAttribute("stroke", COLORS[emotion]);
      arc.setAttribute("stroke-width", "1.5");
      arc.setAttribute("opacity", "0.25");
      arc.setAttribute("d", arcPath(MAX_R, centerAngle));
      svg.appendChild(arc);
      this.outerArcEls[emotion] = arc;

      const [lx, ly] = polar(LABEL_R, centerAngle);
      const label = document.createElementNS("http://www.w3.org/2000/svg", "text");
      label.setAttribute("x", String(lx));
      label.setAttribute("y", String(ly));
      label.setAttribute("text-anchor", "middle");
      label.setAttribute("dominant-baseline", "middle");
      label.setAttribute("font-size", "6");
      label.setAttribute("font-family", "system-ui, sans-serif");
      label.setAttribute("font-weight", "600");
      label.setAttribute("letter-spacing", "0.05em");
      label.setAttribute("fill", COLORS[emotion]);
      label.textContent = LABELS[emotion];
      svg.appendChild(label);
      this.labelEls[emotion] = label;
    });

    const hub = document.createElementNS("http://www.w3.org/2000/svg", "circle");
    hub.setAttribute("cx", String(CX));
    hub.setAttribute("cy", String(CY));
    hub.setAttribute("r", String(HUB_R));
    hub.setAttribute("fill", this.isDark ? "#111111" : "#f0f0f0");
    hub.setAttribute("stroke", this.isDark ? "rgba(255,255,255,0.15)" : "rgba(0,0,0,0.15)");
    hub.setAttribute("stroke-width", "1");
    svg.appendChild(hub);
    this.hubEl = hub;

    container.appendChild(svg);
    this.svg = svg;

    this.mql.addEventListener("change", this.onSchemeChange);
    this.animate();
  }

  private onSchemeChange = (e: MediaQueryListEvent) => {
    this.isDark = e.matches;
    this.bgEl?.setAttribute("fill", this.isDark ? "#000000" : "#ffffff");
    this.refRingEl?.setAttribute("stroke", this.isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.06)");
    this.midRingEl?.setAttribute("stroke", this.isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)");
    this.hubEl?.setAttribute("fill", this.isDark ? "#111111" : "#f0f0f0");
    this.hubEl?.setAttribute("stroke", this.isDark ? "rgba(255,255,255,0.15)" : "rgba(0,0,0,0.15)");
    // Update petal separator strokes
    for (const el of Object.values(this.petalEls)) {
      el?.setAttribute("stroke", this.isDark ? "#000000" : "#ffffff");
    }
  };

  update(state: CollectiveState, config: DisplayConfig, _context?: PageContext) {
    this.lastState = state;
    this.lastConfig = config;
  }

  unmount() {
    if (this.animFrame) cancelAnimationFrame(this.animFrame);
    this.mql.removeEventListener("change", this.onSchemeChange);
    this.svg?.remove();
    this.svg = null;
    this.bgEl = null;
    this.refRingEl = null;
    this.midRingEl = null;
    this.hubEl = null;
    this.petalEls = {};
    this.outerArcEls = {};
    this.labelEls = {};
  }

  private animate() {
    this.animFrame = requestAnimationFrame(() => {
      const s = this.lastState;
      const cfg = this.lastConfig;
      if (s && cfg) {
        this.phase = (this.phase + cfg.motion * 0.005) % (Math.PI * 2);
        this.render(s, cfg);
      }
      this.animate();
    });
  }

  private render(s: CollectiveState, cfg: DisplayConfig) {
    const breathScale = 1 + Math.sin(this.phase) * 0.03 * cfg.motion;
    const showLabels  = cfg.abstraction < 0.65;

    PLUTCHIK_EMOTIONS.forEach((emotion, i) => {
      const intensity    = s.emotions[emotion] ?? 0;
      const centerAngle  = i * SECTOR_DEG;
      const rawR         = HUB_R + (MAX_R - HUB_R) * intensity;
      const r            = rawR * breathScale;
      // Keep petals fully opaque; use solidarity only for a subtle dimming when group is very spread
      const petalOpacity = 0.9 + s.solidarity * 0.1 - s.variance * 0.15;

      const petal = this.petalEls[emotion];
      if (petal) {
        petal.setAttribute("d", petalPath(Math.max(r, HUB_R + 0.5), centerAngle));
        petal.setAttribute("opacity", String(Math.max(0.7, petalOpacity)));
      }

      const label = this.labelEls[emotion];
      if (label) {
        label.setAttribute("opacity", showLabels ? String(0.5 + intensity * 0.5) : "0");
      }
    });
  }
}
