import type { VisualizationMode } from "./index";
import type { CollectiveState, DisplayConfig, PageContext } from "../state/types";

/**
 * Weather — a sky scene driven directly by Plutchik emotions.
 *
 * Mappings:
 *   joy          → sun height + sky warmth
 *   trust        → sky clarity / how blue and open the sky is
 *   sadness      → cloud density, sky going grey-blue
 *   anger        → storm darkness, reddish sky tint
 *   fear         → heavy overcast, dark clouds
 *   anticipation → wind speed (cloud drift rate)
 *   surprise     → occasional lightning flash
 *   disgust      → murky greenish-yellow haze tint
 *   solidarity   → how coherent the weather looks
 *   motion cfg   → overall animation speed multiplier
 *
 * In light mode the neutral sky base is brighter; dark mode uses deeper tones.
 */
export class WeatherViz implements VisualizationMode {
  id = "weather";
  name = "Weather";

  private svg: SVGSVGElement | null = null;
  private animFrame: number | null = null;
  private phase = 0;
  private lastState: CollectiveState | null = null;
  private lastConfig: DisplayConfig | null = null;
  private lightningTimer = 0;

  private isDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
  private mql = window.matchMedia("(prefers-color-scheme: dark)");

  mount(container: HTMLElement, _config: DisplayConfig) {
    const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
    svg.setAttribute("viewBox", "0 0 200 120");
    svg.style.cssText = "width:100%;height:100%;display:block;";
    svg.innerHTML = `
      <defs>
        <radialGradient id="wSunGlow" cx="50%" cy="50%" r="50%">
          <stop offset="0%"   stop-color="#ffe87a" stop-opacity="1"/>
          <stop offset="100%" stop-color="#ff9800" stop-opacity="0"/>
        </radialGradient>
      </defs>
      <rect id="wSky" width="200" height="120" rx="8"/>
      <rect id="wHazeRect" width="200" height="120" rx="8" fill="#8aaa22" opacity="0"/>
      <circle id="wSunGlowCircle" r="32" fill="url(#wSunGlow)" opacity="0.6"/>
      <circle id="wSun" r="14"/>
      <g id="wClouds">
        <ellipse id="wCloud1" rx="28" ry="12" opacity="0.85"/>
        <ellipse id="wCloud2" rx="22" ry="9"  opacity="0.75"/>
        <ellipse id="wCloud3" rx="18" ry="8"  opacity="0.65"/>
      </g>
      <g id="wRain" opacity="0"/>
      <line id="wLightning" x1="110" y1="30" x2="98" y2="55"
            stroke="#fffaaa" stroke-width="2" stroke-linecap="round" opacity="0"/>
    `;
    container.appendChild(svg);
    this.svg = svg;

    this.mql.addEventListener("change", this.onSchemeChange);
    this.animate();
  }

  private onSchemeChange = (e: MediaQueryListEvent) => {
    this.isDark = e.matches;
  };

  update(state: CollectiveState, config: DisplayConfig, _context?: PageContext) {
    this.lastState  = state;
    this.lastConfig = config;
    this.render();
  }

  unmount() {
    if (this.animFrame) cancelAnimationFrame(this.animFrame);
    this.mql.removeEventListener("change", this.onSchemeChange);
    this.svg?.remove();
    this.svg = null;
  }

  private animate() {
    this.animFrame = requestAnimationFrame(() => {
      const speed = (this.lastConfig?.motion ?? 0.5) * 0.008 + 0.001;
      this.phase += speed;
      this.lightningTimer++;
      if (this.lastState) this.render();
      this.animate();
    });
  }

  private render() {
    const svg = this.svg;
    const s   = this.lastState;
    const cfg = this.lastConfig;
    if (!svg || !s || !cfg) return;

    const em = s.emotions;

    // ── Sky colour ─────────────────────────────────────────────────────────
    // In light mode the base lightness starts higher (bright daytime sky)
    const joyEffect   = em.joy;
    const sadEffect   = em.sadness * 0.8 + em.fear * 0.5;
    const angerEffect = em.anger;
    const trustEffect = em.trust;

    const skyHue = 210 + sadEffect * 10 + angerEffect * 30;
    const skySat = Math.max(5, 60 * joyEffect + 30 * trustEffect - 40 * sadEffect - 30 * angerEffect);
    // Light mode: near-white base (85); dark mode: near-black base (8)
    const baseLit = this.isDark ? 8 : 85;
    const skyL    = Math.min(this.isDark ? 60 : 97,
      Math.max(this.isDark ? 4 : 55,
      baseLit + joyEffect * 30 + trustEffect * 8 - sadEffect * 15 - angerEffect * 15 - em.fear * 10));
    set(svg, "wSky", "fill", `hsl(${skyHue},${skySat}%,${skyL}%)`);

    // ── Sun ─────────────────────────────────────────────────────────────────
    const sunX = 100 + Math.sin(this.phase * 0.3) * 8 * cfg.motion;
    const sunY = 115 - joyEffect * 85 - trustEffect * 15 + sadEffect * 20 + em.fear * 25;
    const sunHue = 40 + joyEffect * 15;
    set(svg, "wSun",          "cx",   sunX);
    set(svg, "wSun",          "cy",   sunY);
    set(svg, "wSun",          "fill", `hsl(${sunHue},95%,${55 + joyEffect * 10}%)`);
    set(svg, "wSunGlowCircle","cx",   sunX);
    set(svg, "wSunGlowCircle","cy",   sunY);
    const sunOpacity = Math.max(0, 1 - sadEffect * 0.7 - em.fear * 0.6);
    set(svg, "wSunGlowCircle","opacity", sunOpacity * 0.6);
    set(svg, "wSun",           "opacity", sunOpacity);

    // ── Clouds ──────────────────────────────────────────────────────────────
    const cloudCount   = Math.round((em.sadness + em.fear) * 1.5 + 0.5);
    const cloudOpacity = 0.3 + (em.sadness + em.fear) * 0.5;
    const cloudSpeed   = (em.anticipation * 0.6 + 0.1) * cfg.motion;
    // Light mode clouds are lighter
    const cloudL = this.isDark
      ? Math.max(20, 80 - em.anger * 50 - em.fear * 30)
      : Math.max(60, 92 - em.anger * 30 - em.fear * 20);

    const cloudData = [
      { id: "wCloud1", baseX: 50,  baseY: 38 },
      { id: "wCloud2", baseX: 130, baseY: 52 },
      { id: "wCloud3", baseX: 160, baseY: 30 },
    ];
    cloudData.forEach((c, i) => {
      const drift = Math.sin(this.phase * (0.4 + i * 0.15) + i * 1.5) * 8 * cloudSpeed;
      set(svg, c.id, "cx",      c.baseX + drift);
      set(svg, c.id, "cy",      c.baseY);
      set(svg, c.id, "opacity", i < cloudCount ? String(cloudOpacity) : "0");
      set(svg, c.id, "fill",    `hsl(${skyHue + em.anger * 20},10%,${cloudL}%)`);
    });

    // ── Rain ──────────────────────────────────────────────────────────────
    const rain = svg.getElementById("wRain") as SVGGElement | null;
    if (rain) {
      const rainIntensity = Math.max(em.sadness, em.fear * 0.7);
      const showRain = rainIntensity > 0.4;
      rain.setAttribute("opacity", showRain ? String(rainIntensity * 0.7) : "0");

      if (showRain && rain.children.length === 0) {
        for (let i = 0; i < 8; i++) {
          const line = document.createElementNS("http://www.w3.org/2000/svg", "line");
          const x = 18 + i * 22;
          line.setAttribute("x1", String(x));
          line.setAttribute("y1", "60");
          line.setAttribute("x2", String(x - 3));
          line.setAttribute("y2", "75");
          line.setAttribute("stroke", em.anger > em.sadness ? "#c86060" : "#a0b8d0");
          line.setAttribute("stroke-width", "1.5");
          line.setAttribute("data-x", String(x));
          rain.appendChild(line);
        }
      }
      Array.from(rain.children).forEach((el, i) => {
        const line = el as SVGLineElement;
        const baseX = parseFloat(line.getAttribute("data-x") ?? "0");
        const dropY = ((this.phase * 40 * (0.8 + i * 0.05) + i * 15) % 60) + 60;
        line.setAttribute("y1", String(dropY));
        line.setAttribute("y2", String(dropY + 15));
        line.setAttribute("x1", String(baseX));
        line.setAttribute("x2", String(baseX - 3));
      });
    }

    // ── Lightning ──────────────────────────────────────────────────────────
    const lightningEl = svg.getElementById("wLightning");
    if (lightningEl) {
      const flashChance = (em.anger * 0.4 + em.surprise * 0.5) * cfg.motion;
      if (this.lightningTimer > 60 && Math.random() < flashChance * 0.03) {
        lightningEl.setAttribute("opacity", "1");
        this.lightningTimer = 0;
      } else if (this.lightningTimer > 5) {
        lightningEl.setAttribute("opacity", "0");
      }
    }

    // ── Disgust haze ────────────────────────────────────────────────────────
    const hazeRect = svg.getElementById("wHazeRect");
    if (hazeRect) hazeRect.setAttribute("opacity", String(em.disgust * 0.25));
  }
}

function set(svg: SVGSVGElement, id: string, attr: string, val: string | number) {
  svg.getElementById(id)?.setAttribute(attr, String(val));
}
