import type { VisualizationMode } from "./index";
import type { CollectiveState, DisplayConfig, PageContext } from "../state/types";

/**
 * Plant — growing plant driven by Plutchik emotions.
 *
 * Mappings:
 *   joy          → stem height + bud bloom
 *   trust        → deep healthy green leaves
 *   sadness      → drooping leaves, yellowing color
 *   anger        → red tint on leaves and bud
 *   fear         → extra tremor/shiver on top of normal sway
 *   anticipation → stem leans forward
 *   disgust      → leaves turn sickly pale/grey-green
 *   surprise     → sudden branch/leaf extension
 *   solidarity   → overall plant coherence / stem straightness
 *   motion cfg   → sway amplitude and speed
 */
export class PlantViz implements VisualizationMode {
  id = "plant";
  name = "Plant";

  private svg: SVGSVGElement | null = null;
  private animFrame: number | null = null;
  private phase = 0;
  private lastState: CollectiveState | null = null;
  private lastConfig: DisplayConfig | null = null;

  private bgEl: SVGRectElement | null = null;
  private isDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
  private mql = window.matchMedia("(prefers-color-scheme: dark)");

  private get bgColor() {
    return this.isDark ? "#000000" : "#ffffff";
  }

  mount(container: HTMLElement, _config: DisplayConfig) {
    const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
    svg.setAttribute("viewBox", "0 0 200 120");
    svg.style.cssText = "width:100%;height:100%;display:block;";
    svg.innerHTML = `
      <rect id="plBg" width="200" height="120" rx="8" fill="${this.bgColor}"/>
      <rect x="82" y="100" width="36" height="16" rx="4" fill="#7b5e3a"/>
      <rect x="78" y="98" width="44" height="6" rx="3" fill="#9a7455"/>
      <line id="plStem" x1="100" y1="98" x2="100" y2="70"
            stroke="#3a7a3a" stroke-width="3" stroke-linecap="round"/>
      <ellipse id="plLeafL1" cx="85" cy="80" rx="14" ry="6" opacity="0.9"/>
      <ellipse id="plLeafR1" cx="115" cy="75" rx="14" ry="6" opacity="0.9"/>
      <ellipse id="plLeafL2" cx="82" cy="65" rx="11" ry="5" opacity="0.8"/>
      <ellipse id="plLeafR2" cx="118" cy="62" rx="11" ry="5" opacity="0.8"/>
      <circle id="plBud" cx="100" cy="60" r="5" fill="#a0d060"/>
    `;
    container.appendChild(svg);
    this.svg = svg;
    this.bgEl = svg.getElementById("plBg") as SVGRectElement;

    this.mql.addEventListener("change", this.onSchemeChange);
    this.animate();
  }

  private onSchemeChange = (e: MediaQueryListEvent) => {
    this.isDark = e.matches;
    this.bgEl?.setAttribute("fill", this.bgColor);
  };

  update(state: CollectiveState, config: DisplayConfig, _context?: PageContext) {
    this.lastState  = state;
    this.lastConfig = config;
  }

  unmount() {
    if (this.animFrame) cancelAnimationFrame(this.animFrame);
    this.mql.removeEventListener("change", this.onSchemeChange);
    this.svg?.remove();
    this.svg = null;
    this.bgEl = null;
  }

  private animate() {
    this.animFrame = requestAnimationFrame(() => {
      const s   = this.lastState;
      const cfg = this.lastConfig;
      if (s && cfg) {
        const em = s.emotions;
        const swaySpeed = (em.anticipation * 0.3 + em.surprise * 0.2 + 0.1) * cfg.motion * 0.04;
        this.phase += swaySpeed;
        this.render(s, cfg);
      }
      this.animate();
    });
  }

  private render(s: CollectiveState, cfg: DisplayConfig) {
    const svg = this.svg;
    if (!svg) return;
    const em = s.emotions;

    const stemHeight = 20 + em.joy * 55 + em.trust * 10 - em.sadness * 15 - em.disgust * 8;
    const stemTopY   = 98 - Math.max(10, stemHeight);

    const baseSway   = Math.sin(this.phase) * 5 * cfg.motion * s.solidarity;
    const fearTremor = em.fear > 0.2
      ? Math.sin(this.phase * 7) * em.fear * 4 * cfg.motion
      : 0;
    const lean = em.anticipation * 6;
    const sway = baseSway + fearTremor + lean;

    const stem = svg.getElementById("plStem");
    if (stem) {
      stem.setAttribute("x1", "100");
      stem.setAttribute("y1", "98");
      stem.setAttribute("x2", String(100 + sway));
      stem.setAttribute("y2", String(stemTopY));
      const stemG = Math.round(120 - em.anger * 60);
      stem.setAttribute("stroke", `rgb(40,${stemG},40)`);
    }

    const leafHue = em.anger > em.trust
      ? 30 - em.anger * 20
      : 80 + em.trust * 45 - em.sadness * 30 - em.disgust * 20;
    const leafSat   = 40 + em.trust * 40 - em.disgust * 25 - em.sadness * 15;
    const leafL     = 25 + em.joy * 20 + em.trust * 10 - em.sadness * 10;
    const leafColor = `hsl(${Math.max(10, leafHue)},${Math.max(15, leafSat)}%,${Math.max(15, leafL)}%)`;

    const spread = 8 + s.variance * 10 + em.surprise * 8;
    const droop  = em.sadness * 18 + em.disgust * 8;

    [
      { id: "plLeafL1", cx: 100 - spread,       cy: stemTopY + 18 + droop },
      { id: "plLeafR1", cx: 100 + spread,       cy: stemTopY + 13 + droop },
      { id: "plLeafL2", cx: 100 - spread * 0.7, cy: stemTopY + 5  + droop * 0.5 },
      { id: "plLeafR2", cx: 100 + spread * 0.7, cy: stemTopY + 2  + droop * 0.5 },
    ].forEach(({ id, cx, cy }) => {
      const el = svg.getElementById(id);
      if (el) {
        el.setAttribute("cx",   String(cx + sway * 0.5));
        el.setAttribute("cy",   String(cy));
        el.setAttribute("fill", leafColor);
      }
    });

    const bud = svg.getElementById("plBud");
    if (bud) {
      bud.setAttribute("cx", String(100 + sway));
      bud.setAttribute("cy", String(stemTopY));
      const budR   = Math.max(1.5, 2 + em.joy * 6 - em.fear * 2);
      const budHue = em.anger > em.joy
        ? 10 + em.anger * 10
        : 55 + em.joy * 40 + em.trust * 30;
      bud.setAttribute("r",    String(budR));
      bud.setAttribute("fill", `hsl(${budHue}, 80%, ${40 + em.joy * 20}%)`);
    }
  }
}
