import type { PageContext } from "../state/types";

/**
 * Page context detection — used by task-native visualisations to adapt.
 *
 * detectPageContext() runs in the content script and inspects the current URL.
 * The result is passed to every visualisation's update() call so visualisations
 * can behave differently on GitHub vs. a reading page vs. a generic site.
 *
 * To add a new app type:
 *  1. Add the literal to the AppType union in types.ts
 *  2. Add detection logic here
 *  3. Handle the new type in the visualisations that care about it
 *
 * To add a new code host, append to CODE_HOSTS.
 * To add a new reading pattern, append a regex to READING_PATTERNS.
 */

// Exact hostnames (and their subdomains) that indicate a coding environment
const CODE_HOSTS = [

  "https://algogym-4fecta.pythonanywhere.com/",
  "github.com",
  "gitlab.com",
  "replit.com",
  "codepen.io",
  "codesandbox.io",
  "gitpod.io",
  "vscode.dev",
];

// Regex patterns checked against hostname + pathname for reading environments
const READING_PATTERNS = [
  /^(docs\.|developer\.|wiki\.|medium\.com|substack\.com)/i,
  /\/(docs?|blog|article|post|read)\//i,
];

export function detectPageContext(): PageContext {
  const host = window.location.hostname;
  const path = window.location.pathname;

  // Check exact hostname match and subdomain match (e.g. gist.github.com)
  if (CODE_HOSTS.some((h) => host === h || host.endsWith(`.${h}`))) {
    console.log("page context: code");
    return { appType: "code" };
  }

  if (
    READING_PATTERNS.some((p) =>
      p instanceof RegExp
        ? p.test(host) || p.test(path)
        : host.includes(p)
    )
  ) {
    console.log("page context: reading");
    return { appType: "reading" };
  }
  console.log("page context: generic");
  return { appType: "generic" };
}
