import type { VisualizationMode } from "./index";
import type { CollectiveState, DisplayConfig, PageContext, PlutchikEmotion } from "../state/types";
import { PLUTCHIK_EMOTIONS } from "../state/types";

/**
 * TaskNativeCode — editor-style ambient viz driven by Plutchik emotions.
 *
 * The left rail color reflects the dominant emotion.
 * The status bar shows the dominant emotion name + solidarity score.
 * Adapts to system light/dark mode.
 */

const EMOTION_HUE: Record<PlutchikEmotion, number> = {
  joy:          48,
  trust:        130,
  anticipation: 35,
  fear:         25,
  anger:        5,
  sadness:      220,
  disgust:      80,
  surprise:     190,
};

const EMOTION_LABEL: Record<PlutchikEmotion, string> = {
  joy:          "joy",
  trust:        "trust",
  anticipation: "anticipation",
  fear:         "fear",
  anger:        "anger",
  sadness:      "sadness",
  disgust:      "disgust",
  surprise:     "surprise",
};

export class TaskNativeCodeViz implements VisualizationMode {
  id = "taskNativeCode";
  name = "Code Native";

  private bar: HTMLDivElement | null = null;
  private wrapper: HTMLDivElement | null = null;
  private animFrame: number | null = null;
  private phase = 0;
  private lastState: CollectiveState | null = null;
  private lastConfig: DisplayConfig | null = null;
  private statusLine: HTMLDivElement | null = null;
  private codeLines: HTMLDivElement[] = [];

  private isDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
  private mql = window.matchMedia("(prefers-color-scheme: dark)");

  private get editorBg() { return this.isDark ? "#000000" : "#ffffff"; }
  private get lineBg()   { return this.isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.07)"; }
  private get statusBorder() { return this.isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.08)"; }
  private get statusColor()  { return this.isDark ? "rgba(255,255,255,0.45)" : "rgba(0,0,0,0.5)"; }
  private get barDefault()   { return this.isDark ? "#333" : "#ccc"; }

  mount(container: HTMLElement, _config: DisplayConfig) {
    const bar = document.createElement("div");
    bar.style.cssText = `
      width: 4px;
      height: 100%;
      border-radius: 2px;
      flex-shrink: 0;
      background: ${this.barDefault};
      transition: background 0.6s ease;
      align-self: stretch;
    `;

    const statusLine = document.createElement("div");
    statusLine.style.cssText = `
      position: absolute;
      bottom: 0;
      left: 0;
      right: 0;
      height: 20px;
      display: flex;
      align-items: center;
      padding: 0 8px;
      font-family: 'JetBrains Mono', 'Fira Code', monospace;
      font-size: 10px;
      letter-spacing: 0.05em;
      border-top: 1px solid ${this.statusBorder};
      color: ${this.statusColor};
      gap: 10px;
    `;

    const wrapper = document.createElement("div");
    wrapper.style.cssText = `
      display: flex;
      flex-direction: row;
      width: 100%;
      height: calc(100% - 20px);
      position: relative;
      background: ${this.editorBg};
      border-radius: 8px 8px 0 0;
      overflow: hidden;
    `;

    const codeArea = document.createElement("div");
    codeArea.style.cssText = `
      flex: 1;
      padding: 10px 12px;
      display: flex;
      flex-direction: column;
      gap: 5px;
      overflow: hidden;
    `;
    const LINE_WIDTHS = [60, 80, 45, 90, 55, 70, 35, 75, 50, 65];
    this.codeLines = [];
    LINE_WIDTHS.forEach((w) => {
      const line = document.createElement("div");
      line.style.cssText = `height:6px;width:${w}%;border-radius:3px;background:${this.lineBg};`;
      codeArea.appendChild(line);
      this.codeLines.push(line);
    });

    wrapper.appendChild(bar);
    wrapper.appendChild(codeArea);
    container.appendChild(wrapper);
    container.appendChild(statusLine);
    container.style.position = "relative";

    this.bar        = bar;
    this.wrapper    = wrapper;
    this.statusLine = statusLine;

    this.mql.addEventListener("change", this.onSchemeChange);
    this.animate();
  }

  private onSchemeChange = (e: MediaQueryListEvent) => {
    this.isDark = e.matches;
    if (this.wrapper)    this.wrapper.style.background = this.editorBg;
    if (this.statusLine) {
      this.statusLine.style.borderTop = `1px solid ${this.statusBorder}`;
      this.statusLine.style.color     = this.statusColor;
    }
    for (const line of this.codeLines) {
      line.style.background = this.lineBg;
    }
  };

  update(state: CollectiveState, config: DisplayConfig, _context?: PageContext) {
    this.lastState  = state;
    this.lastConfig = config;
    this.updateStatusLine(state);
  }

  unmount() {
    if (this.animFrame) cancelAnimationFrame(this.animFrame);
    this.mql.removeEventListener("change", this.onSchemeChange);
    this.bar?.parentElement?.remove();
    this.statusLine?.remove();
    this.bar        = null;
    this.wrapper    = null;
    this.statusLine = null;
    this.codeLines  = [];
  }

  private animate() {
    this.animFrame = requestAnimationFrame(() => {
      const s   = this.lastState;
      const cfg = this.lastConfig;
      if (s && cfg) {
        const em = s.emotions;
        const activation = em.anger * 0.5 + em.fear * 0.4 + em.anticipation * 0.3 + em.joy * 0.1;
        this.phase += (activation * 0.5 + 0.05) * cfg.motion * 0.04;
        this.renderBar(s, cfg);
      }
      this.animate();
    });
  }

  private renderBar(s: CollectiveState, cfg: DisplayConfig) {
    const bar = this.bar;
    if (!bar) return;
    const em = s.emotions;

    let dominantEmotion: PlutchikEmotion = "trust";
    let dominantVal = 0;
    for (const e of PLUTCHIK_EMOTIONS) {
      if (em[e] > dominantVal) { dominantVal = em[e]; dominantEmotion = e; }
    }

    const hue         = EMOTION_HUE[dominantEmotion];
    const sat         = 40 + dominantVal * 45;
    const baseLit     = 30 + dominantVal * 20;
    const pulse       = Math.sin(this.phase) * dominantVal * 18 * cfg.motion;
    const flicker     = (Math.random() - 0.5) * (em.anger * 12 + em.fear * 6 + s.variance * 8);
    const lightness   = baseLit + pulse + flicker;
    const opacity     = 0.35 + s.solidarity * 0.55;

    bar.style.background = `hsl(${hue}, ${sat}%, ${Math.max(15, lightness)}%)`;
    bar.style.opacity    = String(opacity);
    bar.style.boxShadow  = `0 0 ${5 + dominantVal * 10}px hsl(${hue},${sat}%,${lightness}%)`;
  }

  private updateStatusLine(s: CollectiveState) {
    const el = this.statusLine;
    if (!el) return;
    const em     = s.emotions;
    const sorted = [...PLUTCHIK_EMOTIONS].sort((a, b) => em[b] - em[a]);
    const top    = sorted[0];
    const second = sorted[1];
    const secondLabel = em[second] > 0.15 ? ` + ${EMOTION_LABEL[second]}` : "";
    el.innerHTML = `
      <span>● ${s.activeCount} active</span>
      <span>${EMOTION_LABEL[top]}${secondLabel}</span>
      <span>sync ${Math.round(s.solidarity * 100)}%</span>
    `;
  }
}
