// ─── Plutchik emotion model ───────────────────────────────────────────────────
//
// The 8 primary emotions from Plutchik's wheel.
// Opposite pairs: joy↔sadness, trust↔disgust, fear↔anger, surprise↔anticipation
//
// To reorder how they appear in the wheel, edit the array order here —
// the wheel visualisation uses this order clockwise from the top.

export const PLUTCHIK_EMOTIONS = [
  "joy",
  "trust",
  "fear",
  "surprise",
  "sadness",
  "disgust",
  "anger",
  "anticipation",
] as const;

export type PlutchikEmotion = (typeof PLUTCHIK_EMOTIONS)[number];

// ─── Raw data (input) ────────────────────────────────────────────────────────
//
// EmotionState is a set of emotions the participant has selected.
// Represented as an array of emotion names for JSON serialisation.
// Example: ["joy", "trust"] means the participant selected joy and trust.

export type EmotionState = PlutchikEmotion[];

export type ParticipantState = {
  id: string;            // opaque — never shown in visualisations
  state: EmotionState;
};

export type SessionData = {
  participants: ParticipantState[];
  updatedAt: string;     // ISO 8601 timestamp
};

// ─── Aggregated (what visualisations consume) ─────────────────────────────────
//
// Visualisations must ONLY read CollectiveState — never raw participant data.
//
// `emotions` — fraction of participants who selected each emotion [0, 1]
// `participantEmotions` — per-participant selected emotion sets (no IDs)
// `avgValence` / `avgArousal` — derived from emotions via Russell circumplex
//
// To add a new derived signal, add it here and compute it in aggregate.ts.

export type CollectiveState = {
  emotions: Record<PlutchikEmotion, number>; // fraction who selected each [0, 1]
  // Anonymised per-participant emotion sets (no IDs — safe for visualisations).
  participantEmotions: EmotionState[];
  avgValence: number;    // [-1, 1] derived from emotions
  avgArousal: number;    // [0, 1]  derived from emotions
  variance: number;      // [0, 1]  how spread-apart participants are
  solidarity: number;    // [0, 1]  inverse of variance
  activeCount: number;
};

// ─── Display config (experiment controls) ────────────────────────────────────
//
// To add a new control, add the field here, wire it up in Controls.tsx,
// and consume it in the relevant visualisation's update() method.

export type VisualizationMode =
  | "weather"
  | "pulse"
  | "plant"
  | "taskNativeCode"
  | "plutchikWheel"
  | "participants"
  | "bst"
  | "emoji";

export type PlacementMode = "corner" | "edge" | "overlay";
export type DataSourceMode = "static" | "mock" | "manual";

export type DisplayConfig = {
  mode: VisualizationMode;
  abstraction: number;   // [0, 1]  0 = literal, 1 = abstract/ambient
  motion: number;        // [0, 1]  scales animation intensity
  granularity: number;   // [0, 1]  0 = individual per-person, 1 = fully aggregated
  placement: PlacementMode;
  taskNative: boolean;
};

// ─── Page context ─────────────────────────────────────────────────────────────

export type AppType = "code" | "reading" | "generic";

export type PageContext = {
  appType: AppType;
};

// ─── Messages ─────────────────────────────────────────────────────────────────

export type Message =
  | { type: "STATE_UPDATE"; collective: CollectiveState; config: DisplayConfig }
  | { type: "PING" }
  | { type: "PONG" };
