import { OverlayHost } from "./OverlayHost";
import { detectPageContext } from "../utils/pageContext";
import type { Message, CollectiveState, DisplayConfig } from "../state/types";
import { PLUTCHIK_EMOTIONS } from "../state/types";

/**
 * Content script — injected into every http/https page.
 *
 * Responsibilities:
 *  1. Eagerly mount the overlay widget with a default "calm" state so something
 *     is always visible, even before the side panel is opened.
 *  2. Listen for STATE_UPDATE messages from the side panel and forward them
 *     to the OverlayHost for rendering.
 *
 * The content script does NOT own any state — it is purely a renderer.
 * All state logic lives in the side panel (src/sidepanel/index.tsx).
 *
 * To respond to a new message type, add a case to the onMessage listener
 * and define the message shape in src/state/types.ts.
 */

// ── Default state ─────────────────────────────────────────────────────────────
// Shown immediately on page load, before the side panel sends its first update.
// Edit these to change the "idle" appearance of the widget.

const DEFAULT_COLLECTIVE: CollectiveState = {
  emotions: Object.fromEntries(
    PLUTCHIK_EMOTIONS.map((e) => [e, e === "joy" ? 0.5 : e === "trust" ? 0.3 : 0.05])
  ) as CollectiveState["emotions"],
  participantEmotions: [],
  avgValence: 0.3,
  avgArousal: 0.4,
  variance: 0.1,
  solidarity: 0.8,
  activeCount: 5,
};

const DEFAULT_CONFIG: DisplayConfig = {
  mode: "plutchikWheel",
  abstraction: 0.5,
  motion: 0.5,
  granularity: 0.5,
  placement: "corner",
  taskNative: false,
};

// ── Initialise overlay ────────────────────────────────────────────────────────

// Page context is detected once at load time (URL doesn't change mid-session)
const context = detectPageContext();

const overlay = new OverlayHost();
overlay.update(DEFAULT_COLLECTIVE, DEFAULT_CONFIG, context);

// ── Message listener ──────────────────────────────────────────────────────────

chrome.runtime.onMessage.addListener((message: Message, _sender, sendResponse) => {
  if (message.type === "PING") {
    // Used by the side panel to check if the content script is alive on this tab
    sendResponse({ type: "PONG" });
    return;
  }

  if (message.type === "STATE_UPDATE") {
    // Delegate entirely to the OverlayHost — no state kept here
    overlay.update(message.collective, message.config, context);
  }
});
