import type { VisualizationMode } from "./index";
import type { CollectiveState, DisplayConfig, PageContext, PlutchikEmotion } from "../state/types";
import { PLUTCHIK_EMOTIONS } from "../state/types";
import { EMOTION_RGB } from "./participants";

/**
 * Pulse — ripple rings visualisation with three granularity modes:
 *
 *   0 – 0.33  Individual:  one pulse centre per participant, colored by their emotions
 *   0.33–0.67 Grouped:     one pulse centre per emotion present, sized by count
 *   0.67–1    Aggregated:  single centre (original behaviour)
 *
 * Aggregated mappings (all modes use these for colour/speed):
 *   anger/fear/anticipation → fast pulse, warm hue
 *   trust/sadness → slow steady pulse, cool hue
 *   surprise → burst ring (aggregated only)
 *   solidarity → ring coherence
 */

type GranMode = "individual" | "grouped" | "aggregated";

function getGranMode(g: number): GranMode {
  if (g < 0.33) return "individual";
  if (g < 0.67) return "grouped";
  return "aggregated";
}

function blendPulseColor(emotions: PlutchikEmotion[]): { color: string; arousal: number } {
  if (emotions.length === 0) return { color: "hsl(220,40%,30%)", arousal: 0.15 };
  let r = 0, g = 0, b = 0;
  for (const e of emotions) {
    const [er, eg, eb] = EMOTION_RGB[e];
    r += er; g += eg; b += eb;
  }
  r = Math.round(r / emotions.length);
  g = Math.round(g / emotions.length);
  b = Math.round(b / emotions.length);
  const activating = new Set(["anger", "fear", "anticipation", "surprise", "joy"]);
  const arousal = Math.min(1, emotions.filter((e) => activating.has(e)).length * 0.28);
  return { color: `rgb(${r},${g},${b})`, arousal: Math.max(0.05, arousal) };
}

// ── Source: one pulsing unit ─────────────────────────────────────────────────

interface PulseSource {
  cx: number;
  cy: number;
  rings: SVGCircleElement[];
  center: SVGCircleElement;
  phase: number;
  color: string;
  arousal: number;
  maxR: number;
}

// ── Layout for individual/grouped ─────────────────────────────────────────────

function gridCenters(n: number, w: number, h: number): Array<{ cx: number; cy: number }> {
  if (n === 0) return [];
  const pad = 12;
  let bestCols = 1;
  let bestR = 0;
  for (let cols = 1; cols <= n; cols++) {
    const rows = Math.ceil(n / cols);
    const rW = (w - pad * (cols + 1)) / (2 * cols);
    const rH = (h - pad * (rows + 1)) / (2 * rows);
    const r = Math.min(rW, rH);
    if (r > bestR) { bestR = r; bestCols = cols; }
  }
  const bestRows = Math.ceil(n / bestCols);
  const cellW = (w - pad * (bestCols + 1)) / bestCols;
  const cellH = (h - pad * (bestRows + 1)) / bestRows;
  const offX = pad + cellW / 2;
  const offY = pad + cellH / 2;
  return Array.from({ length: n }, (_, i) => ({
    cx: offX + (i % bestCols) * (cellW + pad),
    cy: offY + Math.floor(i / bestCols) * (cellH + pad),
  }));
}

function ringCenter(idx: number, total: number, w: number, h: number): { cx: number; cy: number } {
  const angle = (idx / total) * Math.PI * 2 - Math.PI / 2;
  return {
    cx: w / 2 + w * 0.32 * Math.cos(angle),
    cy: h / 2 + h * 0.32 * Math.sin(angle),
  };
}

export class PulseViz implements VisualizationMode {
  id = "pulse";
  name = "Pulse";

  private svg: SVGSVGElement | null = null;
  private bgRect: SVGRectElement | null = null;
  private animFrame: number | null = null;
  private lastState: CollectiveState | null = null;
  private lastConfig: DisplayConfig | null = null;
  private lastGranMode: GranMode | null = null;
  private lastCount = -1;

  private sources: PulseSource[] = [];

  // Aggregated-only extras
  private burstRing: SVGCircleElement | null = null;
  private burstPhase = -1;
  private phase = 0; // global phase for aggregated

  private isDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
  private mql = window.matchMedia("(prefers-color-scheme: dark)");

  mount(container: HTMLElement, _config: DisplayConfig) {
    const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
    svg.setAttribute("viewBox", "0 0 200 120");
    svg.style.cssText = "width:100%;height:100%;display:block;";

    const bg = document.createElementNS("http://www.w3.org/2000/svg", "rect");
    bg.setAttribute("width", "200");
    bg.setAttribute("height", "120");
    bg.setAttribute("rx", "8");
    bg.setAttribute("fill", this.isDark ? "#000000" : "#ffffff");
    svg.appendChild(bg);
    this.bgRect = bg;

    // Burst ring (aggregated mode only — hidden otherwise)
    const burst = document.createElementNS("http://www.w3.org/2000/svg", "circle");
    burst.setAttribute("id", "pBurst");
    burst.setAttribute("cx", "100");
    burst.setAttribute("cy", "60");
    burst.setAttribute("r",  "0");
    burst.setAttribute("fill", "none");
    burst.setAttribute("stroke", "#ffffff");
    burst.setAttribute("stroke-width", "2");
    burst.setAttribute("opacity", "0");
    svg.appendChild(burst);
    this.burstRing = burst;

    container.appendChild(svg);
    this.svg = svg;

    this.mql.addEventListener("change", this.onSchemeChange);
    this.animate();
  }

  private onSchemeChange = (e: MediaQueryListEvent) => {
    this.isDark = e.matches;
    if (this.bgRect) this.bgRect.setAttribute("fill", this.isDark ? "#000000" : "#ffffff");
  };

  update(state: CollectiveState, config: DisplayConfig, _context?: PageContext) {
    // Surprise burst (aggregated only)
    if (this.lastState && getGranMode(config.granularity) === "aggregated") {
      if (state.emotions.surprise > this.lastState.emotions.surprise + 0.15 && this.burstPhase < 0) {
        this.burstPhase = 0;
      }
    }
    this.lastState  = state;
    this.lastConfig = config;

    const granMode    = getGranMode(config.granularity);
    const countChanged = state.participantEmotions.length !== this.lastCount;
    const modeChanged  = granMode !== this.lastGranMode;
    if (countChanged || modeChanged) {
      this.rebuild(state, granMode);
      this.lastGranMode = granMode;
    }
  }

  unmount() {
    if (this.animFrame) cancelAnimationFrame(this.animFrame);
    this.mql.removeEventListener("change", this.onSchemeChange);
    this.svg?.remove();
    this.svg = null;
    this.bgRect = null;
    this.sources = [];
    this.burstRing = null;
  }

  // ── Rebuild ────────────────────────────────────────────────────────────────

  private clearSources() {
    if (!this.svg) return;
    // Remove source elements but keep bg and burst
    for (const src of this.sources) {
      for (const r of src.rings) r.remove();
      src.center.remove();
    }
    this.sources = [];
  }

  private makeSource(
    cx: number, cy: number, color: string, arousal: number, maxR: number, numRings = 4
  ): PulseSource {
    const svg = this.svg!;
    const rings: SVGCircleElement[] = [];
    for (let i = 0; i < numRings; i++) {
      const ring = document.createElementNS("http://www.w3.org/2000/svg", "circle");
      ring.setAttribute("cx", String(cx));
      ring.setAttribute("cy", String(cy));
      ring.setAttribute("r",  "0");
      ring.setAttribute("fill", "none");
      ring.setAttribute("stroke-width", "1.2");
      // Insert before burst ring so burst stays on top
      svg.insertBefore(ring, this.burstRing);
      rings.push(ring);
    }
    const center = document.createElementNS("http://www.w3.org/2000/svg", "circle");
    center.setAttribute("cx", String(cx));
    center.setAttribute("cy", String(cy));
    center.setAttribute("r",  "3");
    center.setAttribute("fill", color);
    svg.insertBefore(center, this.burstRing);

    return { cx, cy, rings, center, phase: Math.random(), color, arousal, maxR };
  }

  private rebuild(state: CollectiveState, mode: GranMode) {
    this.clearSources();
    this.lastCount = state.participantEmotions.length;
    this.phase = 0;
    this.burstPhase = -1;

    if (this.burstRing) this.burstRing.setAttribute("opacity", "0");

    if (mode === "individual") {
      const centers = gridCenters(state.participantEmotions.length, 200, 120);
      state.participantEmotions.forEach((emotions, i) => {
        const { color, arousal } = blendPulseColor(emotions);
        const maxR = Math.min(200, 120) * 0.14;
        const pos  = centers[i] ?? { cx: 100, cy: 60 };
        this.sources.push(this.makeSource(pos.cx, pos.cy, color, arousal, maxR));
      });
    } else if (mode === "grouped") {
      const active = PLUTCHIK_EMOTIONS.filter((e) =>
        state.participantEmotions.some((s) => s.includes(e))
      );
      active.forEach((emotion, idx) => {
        const count = state.participantEmotions.filter((s) => s.includes(emotion)).length;
        const pos   = ringCenter(idx, active.length, 200, 120);
        const [er, eg, eb] = EMOTION_RGB[emotion];
        const color = `rgb(${er},${eg},${eb})`;
        const fraction = count / Math.max(1, state.activeCount);
        const maxR = 12 + fraction * 18;
        const src = this.makeSource(pos.cx, pos.cy, color, 0.3 + fraction * 0.4, maxR);
        // Tag center with fraction for sizing
        src.center.dataset["fraction"] = String(fraction);
        this.sources.push(src);
      });
    } else {
      // Aggregated: single source at centre with 5 rings
      this.sources.push(this.makeSource(100, 60, "hsl(220,50%,40%)", 0.3, 40, 5));
    }
  }

  // ── Animation ──────────────────────────────────────────────────────────────

  private animate() {
    this.animFrame = requestAnimationFrame(() => {
      const s   = this.lastState;
      const cfg = this.lastConfig;
      if (s && cfg) {
        const mode = getGranMode(cfg.granularity);
        if (mode === "individual") this.renderSources(s, cfg, false);
        else if (mode === "grouped") this.renderSources(s, cfg, true);
        else this.renderAggregated(s, cfg);
      }
      this.animate();
    });
  }

  private renderSources(s: CollectiveState, cfg: DisplayConfig, isGrouped: boolean) {
    // Hide burst ring in non-aggregated modes
    if (this.burstRing) this.burstRing.setAttribute("opacity", "0");

    this.sources.forEach((src) => {
      src.phase = (src.phase + src.arousal * 0.025 * cfg.motion) % 1;

      src.rings.forEach((ring, i) => {
        const offset  = (src.phase + i / src.rings.length) % 1;
        const r       = offset * src.maxR;
        const opacity = (1 - offset) * (0.4 + s.solidarity * 0.4);
        ring.setAttribute("r",       String(r));
        ring.setAttribute("stroke",  src.color);
        ring.setAttribute("opacity", String(Math.max(0, opacity)));
      });

      // Center dot pulse
      const throb = 0.8 + Math.sin(src.phase * Math.PI * 2) * 0.3 * cfg.motion;
      const dotR  = isGrouped
        ? (2 + parseFloat(src.center.dataset["fraction"] ?? "0.5") * 4) * throb
        : 2.5 * throb;
      src.center.setAttribute("r",    String(dotR));
      src.center.setAttribute("fill", src.color);
    });
  }

  private renderAggregated(s: CollectiveState, cfg: DisplayConfig) {
    const em = s.emotions;
    const activation = em.anger * 0.5 + em.fear * 0.4 + em.anticipation * 0.3
                     + em.joy * 0.2 - em.sadness * 0.15 - em.disgust * 0.1;
    const speed = (Math.max(0.05, activation) * 0.5 + 0.1) * cfg.motion;
    this.phase = (this.phase + speed * 0.03) % 1;

    if (this.burstPhase >= 0) this.burstPhase += 0.04 * cfg.motion;
    if (this.burstPhase > 1)  this.burstPhase = -1;

    const src = this.sources[0];
    if (!src) return;

    const total = em.joy + em.anger + em.sadness + em.trust + em.fear + 0.001;
    const hue   = (em.joy * 55 + em.anger * 5 + em.sadness * 220 + em.trust * 130 + em.fear * 30) / total;
    const sat   = 60 + (em.joy + em.anger + em.surprise) * 20 - em.disgust * 20;
    const lit   = 45 + em.joy * 15 - em.sadness * 10 - em.anger * 5;
    const color = `hsl(${hue},${Math.max(20, sat)}%,${Math.max(25, lit)}%)`;

    const maxR  = 25 + s.solidarity * 15 + em.joy * 10 - em.disgust * 8 - em.sadness * 5;

    src.rings.forEach((ring, i) => {
      const offset = ((this.phase + i / src.rings.length) % 1);
      const r       = offset * maxR;
      const opacity = (1 - offset) * (0.35 + s.solidarity * 0.55);
      const wobble  = 1 + (s.variance + em.disgust * 0.5) * Math.sin(this.phase * 10 + i) * 1.5;
      ring.setAttribute("r",            String(r));
      ring.setAttribute("stroke",       color);
      ring.setAttribute("stroke-width", String(Math.max(0.5, wobble)));
      ring.setAttribute("opacity",      String(Math.max(0, opacity)));
    });

    // Burst (surprise)
    if (this.burstRing && this.burstPhase >= 0) {
      const br = this.burstPhase * maxR * 1.8;
      const bo = Math.max(0, (1 - this.burstPhase) * em.surprise);
      this.burstRing.setAttribute("r",       String(br));
      this.burstRing.setAttribute("opacity", String(bo));
      this.burstRing.setAttribute("stroke",  `hsl(${hue}, 80%, 75%)`);
    } else if (this.burstRing) {
      this.burstRing.setAttribute("opacity", "0");
    }

    // Centre dot
    const throb = em.anger * 0.4 + em.fear * 0.3 + em.joy * 0.2;
    const r = 4 + throb * 4 + Math.sin(this.phase * Math.PI * 2) * 2 * cfg.motion;
    src.center.setAttribute("fill", color);
    src.center.setAttribute("r",    String(r));
  }
}
